#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Open the PDF file
my $pdf = PDF::API2->open('input.pdf');

# Get the first page
my $page = $pdf->openpage(1);

# Extract text from the page
my @text = $page->text;

# Initialize variables to store extracted information
my ($date, $author, $table_info);

# Process the text to extract specific information
foreach my $line (@text) {
    if ($line =~ /Date:\s*(\d{2}\/\d{2}\/\d{4})/) {
        $date = $1;
    }
    if ($line =~ /Author:\s*(\w+)/) {
        $author = $1;
    }
    if ($line =~ /Table/) {
        $table_info .= $line . "\n";
    }
}

# Output the extracted information
print "Date: $date\n" if $date;
print "Author: $author\n" if $author;
print "Table Information:\n$table_info" if $table_info;

# Cleanup
$pdf->close;
```

